#include <stdio.h>

int main() {
    int m, n;
    scanf("%d %d", &m, &n);

    long long sum = 0;
    for (int i = m; i <= n; i++) {
        if (i % 15 == 0) {
            sum += i;
        }
    }
    printf("%lld\n", sum);
    return 0;
}

