import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);

        int m = sc.nextInt();
        int n = sc.nextInt();

        long sum = 0;
        for (int i = m; i <= n; i++) {
            if (i % 15 == 0) {
                sum += i;
            }
        }

        System.out.println(sum);
        sc.close();
    }
}
